import React, { useState } from 'react';
import { Heart, MessageCircle, Repeat2, Share2, Image as ImageIcon, Smile, MapPin } from 'lucide-react';
import { MOCK_POSTS, CURRENT_USER } from '../constants';
import { Post } from '../types';

export const Feed: React.FC = () => {
  const [posts, setPosts] = useState<Post[]>(MOCK_POSTS);
  const [newPostContent, setNewPostContent] = useState('');

  const handlePost = () => {
    if (!newPostContent.trim()) return;

    const newPost: Post = {
      id: Date.now().toString(),
      user: CURRENT_USER,
      content: newPostContent,
      timestamp: 'Agora',
      likes: 0,
      comments: 0,
      retweets: 0,
    };

    setPosts([newPost, ...posts]);
    setNewPostContent('');
  };

  return (
    <div className="flex-1 border-r border-gray-200 min-h-screen">
      {/* Header */}
      <div className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-gray-200 px-4 py-3">
        <h2 className="text-xl font-bold text-gray-900">Página Inicial</h2>
      </div>

      {/* Post Creator */}
      <div className="px-4 py-3 border-b border-gray-200">
        <div className="flex gap-4">
          <img 
            src={CURRENT_USER.avatar} 
            alt="Avatar" 
            className="w-12 h-12 rounded-full object-cover"
          />
          <div className="flex-1">
            <textarea
              className="w-full text-lg text-gray-900 placeholder-gray-500 focus:outline-none resize-none mt-2"
              placeholder="O que está acontecendo na militância?"
              rows={2}
              value={newPostContent}
              onChange={(e) => setNewPostContent(e.target.value)}
            />
            <div className="flex justify-between items-center mt-3">
              <div className="flex gap-2 text-red-600">
                <button className="p-2 hover:bg-red-50 rounded-full transition-colors"><ImageIcon size={20} /></button>
                <button className="p-2 hover:bg-red-50 rounded-full transition-colors"><Smile size={20} /></button>
                <button className="p-2 hover:bg-red-50 rounded-full transition-colors"><MapPin size={20} /></button>
              </div>
              <button 
                onClick={handlePost}
                disabled={!newPostContent.trim()}
                className="bg-red-600 hover:bg-red-700 text-white font-bold py-2 px-6 rounded-full disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                Postar
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Posts List */}
      <div className="pb-20">
        {posts.map((post) => (
          <article key={post.id} className="p-4 border-b border-gray-200 hover:bg-gray-50 transition-colors cursor-pointer">
            <div className="flex gap-4">
              <img 
                src={post.user.avatar} 
                alt={post.user.name} 
                className="w-12 h-12 rounded-full object-cover"
              />
              <div className="flex-1">
                <div className="flex items-center gap-2">
                  <span className="font-bold text-gray-900">{post.user.name}</span>
                  {post.user.isVerified && (
                    <span className="text-red-600" title="Verificado">★</span>
                  )}
                  <span className="text-gray-500 text-sm">{post.user.handle} · {post.timestamp}</span>
                </div>
                <p className="text-gray-900 mt-1 whitespace-pre-wrap leading-relaxed">
                  {post.content}
                </p>
                {post.image && (
                  <img 
                    src={post.image} 
                    alt="Post content" 
                    className="mt-3 rounded-2xl w-full border border-gray-200 object-cover max-h-80"
                  />
                )}
                <div className="flex justify-between mt-3 max-w-md text-gray-500">
                  <button className="flex items-center gap-2 group hover:text-blue-500">
                    <div className="p-2 group-hover:bg-blue-50 rounded-full transition-colors">
                      <MessageCircle size={18} />
                    </div>
                    <span className="text-sm">{post.comments}</span>
                  </button>
                  <button className="flex items-center gap-2 group hover:text-green-500">
                    <div className="p-2 group-hover:bg-green-50 rounded-full transition-colors">
                      <Repeat2 size={18} />
                    </div>
                    <span className="text-sm">{post.retweets}</span>
                  </button>
                  <button className="flex items-center gap-2 group hover:text-red-600">
                    <div className="p-2 group-hover:bg-red-50 rounded-full transition-colors">
                      <Heart size={18} />
                    </div>
                    <span className="text-sm">{post.likes}</span>
                  </button>
                  <button className="flex items-center gap-2 group hover:text-blue-500">
                    <div className="p-2 group-hover:bg-blue-50 rounded-full transition-colors">
                      <Share2 size={18} />
                    </div>
                  </button>
                </div>
              </div>
            </div>
          </article>
        ))}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MapCategory, MapPoint } from '../types';
import { MAP_POINTS } from '../constants';
import { MapPin, Users, Flag, HeartHandshake, Tent } from 'lucide-react';

export const MapViz: React.FC = () => {
  const [selectedCategory, setSelectedCategory] = useState<MapCategory | 'ALL'>('ALL');
  const [activePoint, setActivePoint] = useState<MapPoint | null>(null);

  const filteredPoints = selectedCategory === 'ALL' 
    ? MAP_POINTS 
    : MAP_POINTS.filter(p => p.category === selectedCategory);

  const getIcon = (category: MapCategory) => {
    switch (category) {
      case MapCategory.MST_COMMUNITY: return <Tent size={20} className="text-white" />;
      case MapCategory.LEADERSHIP: return <Users size={20} className="text-white" />;
      case MapCategory.DONATION: return <HeartHandshake size={20} className="text-white" />;
      case MapCategory.MEETING_POINT: return <MapPin size={20} className="text-white" />;
      default: return <Flag size={20} className="text-white" />;
    }
  };

  const getColor = (category: MapCategory) => {
    switch (category) {
      case MapCategory.MST_COMMUNITY: return 'bg-green-700 border-green-900';
      case MapCategory.LEADERSHIP: return 'bg-red-600 border-red-800';
      case MapCategory.DONATION: return 'bg-yellow-500 border-yellow-700';
      case MapCategory.MEETING_POINT: return 'bg-blue-500 border-blue-700';
      default: return 'bg-gray-500';
    }
  };

  return (
    <div className="flex-1 flex flex-col h-screen border-r border-gray-200">
      <div className="p-4 border-b border-gray-200 bg-white sticky top-0 z-10">
        <h2 className="text-xl font-bold text-gray-900 mb-4">Mapa da Militância - Betim/MG</h2>

        {/* Filters */}
        <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
          <button 
            onClick={() => setSelectedCategory('ALL')}
            className={`px-4 py-1.5 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${selectedCategory === 'ALL' ? 'bg-gray-900 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
          >
            Todos
          </button>
          {Object.values(MapCategory).map((cat) => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`px-4 py-1.5 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${selectedCategory === cat ? 'bg-red-600 text-white' : 'bg-red-50 text-red-700 hover:bg-red-100'}`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="relative flex-1 bg-slate-100 overflow-hidden group">
        {/* Mock Map Background - Schematic */}
        <div className="absolute inset-0 opacity-10 pointer-events-none bg-[url('https://upload.wikimedia.org/wikipedia/commons/e/ec/Betim_Minas_Gerais_Brazil_Map.svg')] bg-cover bg-center" />

        <div className="absolute inset-0 grid grid-cols-12 grid-rows-12 pointer-events-none">
           {/* Grid lines for "tech" map feel */}
           {Array.from({ length: 144 }).map((_, i) => (
             <div key={i} className="border-[0.5px] border-gray-300 opacity-20" />
           ))}
        </div>

        {/* Info Label */}
        <div className="absolute bottom-4 right-4 bg-white/90 backdrop-blur px-3 py-2 rounded-lg text-xs text-gray-500 shadow-sm border border-gray-200">
          Visualização Esquemática • Betim
        </div>

        {/* Map Points */}
        {filteredPoints.map((point) => (
          <button
            key={point.id}
            onClick={() => setActivePoint(point)}
            className={`absolute transform -translate-x-1/2 -translate-y-1/2 transition-all duration-300 hover:scale-125 hover:z-50 ${getColor(point.category)} rounded-full p-2 border-2 shadow-lg`}
            style={{ 
              top: `${point.lat}%`, 
              left: `${point.lng}%`,
            }}
          >
            {getIcon(point.category)}
          </button>
        ))}

        {/* Active Point Modal/Card */}
        {activePoint && (
          <div className="absolute bottom-0 left-0 right-0 p-4 animate-in slide-in-from-bottom-10 fade-in duration-300">
            <div className="bg-white rounded-2xl shadow-2xl p-4 border border-gray-200 relative">
              <button 
                onClick={() => setActivePoint(null)}
                className="absolute top-2 right-2 text-gray-400 hover:text-gray-600 p-1"
              >
                ✕
              </button>
              <div className="flex items-start gap-4">
                <div className={`p-3 rounded-xl ${getColor(activePoint.category).split(' ')[0]}`}>
                   {getIcon(activePoint.category)}
                </div>
                <div>
                  <h3 className="font-bold text-lg text-gray-900">{activePoint.title}</h3>
                  <span className="text-xs font-semibold text-red-600 uppercase tracking-wide">{activePoint.category}</span>
                  <p className="text-gray-600 mt-1 text-sm">{activePoint.description}</p>
                  <div className="mt-3 flex items-center text-gray-500 text-xs">
                    <MapPin size={12} className="mr-1" />
                    {activePoint.address}
                  </div>
                </div>
              </div>
              <div className="mt-4 flex gap-2">
                <button className="flex-1 bg-red-600 text-white py-2 rounded-lg text-sm font-semibold hover:bg-red-700 transition-colors">
                  Ver Detalhes
                </button>
                <button className="flex-1 bg-gray-100 text-gray-700 py-2 rounded-lg text-sm font-semibold hover:bg-gray-200 transition-colors">
                  Traçar Rota
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Home, Map as MapIcon, User, Bell, PenSquare, LogOut, Star } from 'lucide-react';
import { Feed } from './components/Feed';
import { MapViz } from './components/MapViz';
import { Trends } from './components/Trends';
import { CURRENT_USER } from './constants';

enum View {
  HOME = 'HOME',
  MAP = 'MAP',
  PROFILE = 'PROFILE',
  NOTIFICATIONS = 'NOTIFICATIONS'
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.HOME);

  // Mobile Bottom Navigation Item
  const MobileNavItem = ({ view, icon: Icon, label }: { view: View, icon: any, label: string }) => (
    <button 
      onClick={() => setCurrentView(view)}
      className={`flex flex-col items-center justify-center p-2 flex-1 ${currentView === view ? 'text-red-600' : 'text-gray-500'}`}
    >
      <Icon size={24} fill={currentView === view ? 'currentColor' : 'none'} />
      <span className="text-xs mt-1 font-medium">{label}</span>
    </button>
  );

  // Desktop Sidebar Item
  const SidebarItem = ({ view, icon: Icon, label }: { view: View, icon: any, label: string }) => (
    <button 
      onClick={() => setCurrentView(view)}
      className={`flex items-center gap-4 px-4 py-3 w-full rounded-full transition-all duration-200 ${
        currentView === view 
          ? 'font-bold text-gray-900 bg-gray-100' 
          : 'text-gray-700 hover:bg-gray-100'
      }`}
    >
      <Icon size={26} strokeWidth={currentView === view ? 2.5 : 2} />
      <span className="text-xl hidden xl:block">{label}</span>
    </button>
  );

  return (
    <div className="flex justify-center min-h-screen bg-white">
      <div className="flex w-full max-w-[1300px]">

        {/* Left Sidebar (Desktop) */}
        <header className="hidden sm:flex flex-col justify-between w-[80px] xl:w-[280px] p-4 h-screen sticky top-0 border-r border-gray-200">
          <div className="flex flex-col gap-2">
            {/* Logo */}
            <div className="pl-2 xl:pl-4 mb-4">
              <div className="w-12 h-12 bg-red-600 rounded-lg flex items-center justify-center text-white cursor-pointer hover:bg-red-700 transition-colors">
                <Star size={32} fill="white" />
              </div>
            </div>

            <nav className="flex flex-col gap-2">
              <SidebarItem view={View.HOME} icon={Home} label="Início" />
              <SidebarItem view={View.MAP} icon={MapIcon} label="Mapa Militância" />
              <SidebarItem view={View.NOTIFICATIONS} icon={Bell} label="Notificações" />
              <SidebarItem view={View.PROFILE} icon={User} label="Perfil" />
            </nav>

            <button className="mt-8 bg-red-600 hover:bg-red-700 text-white rounded-full p-4 xl:py-3 xl:px-8 font-bold shadow-lg transition-transform hover:scale-105 flex justify-center items-center">
              <PenSquare className="xl:hidden" size={24} />
              <span className="hidden xl:block text-lg">Militar</span>
            </button>
          </div>

          <div className="mt-auto flex items-center gap-3 p-3 rounded-full hover:bg-gray-100 cursor-pointer transition-colors">
            <img 
              src={CURRENT_USER.avatar} 
              alt="User" 
              className="w-10 h-10 rounded-full"
            />
            <div className="hidden xl:block flex-1">
              <p className="font-bold text-sm text-gray-900 leading-tight">{CURRENT_USER.name}</p>
              <p className="text-gray-500 text-sm">{CURRENT_USER.handle}</p>
            </div>
            <LogOut size={18} className="hidden xl:block text-gray-500" />
          </div>
        </header>

        {/* Main Content Area */}
        <main className="flex-1 w-full max-w-[600px] min-h-screen relative pb-16 sm:pb-0">
          {currentView === View.HOME && <Feed />}
          {currentView === View.MAP && <MapViz />}
          {currentView === View.NOTIFICATIONS && (
            <div className="p-8 text-center text-gray-500">
              <Bell size={48} className="mx-auto mb-4 opacity-50" />
              <h2 className="text-xl font-bold mb-2">Sem novas notificações</h2>
              <p>Quando houver novidades sobre a militância, elas aparecerão aqui.</p>
            </div>
          )}
          {currentView === View.PROFILE && (
            <div className="flex flex-col h-full">
               <div className="h-32 bg-red-600"></div>
               <div className="px-4 pb-4 border-b border-gray-200">
                  <div className="relative -mt-16 mb-3">
                    <img src={CURRENT_USER.avatar} className="w-32 h-32 rounded-full border-4 border-white" />
                  </div>
                  <h1 className="text-2xl font-bold">{CURRENT_USER.name}</h1>
                  <p className="text-gray-500">{CURRENT_USER.handle}</p>
                  <p className="mt-3 text-gray-900">Militante ativo em Betim/MG. Lutando por um Brasil mais justo. 🚩⭐</p>
                  <div className="flex gap-4 mt-3 text-sm text-gray-500">
                    <span><strong className="text-gray-900">540</strong> Seguindo</span>
                    <span><strong className="text-gray-900">1.2M</strong> Seguidores</span>
                  </div>
               </div>
               <div className="p-8 text-center text-gray-500">
                 <p>Histórico de posts carregando...</p>
               </div>
            </div>
          )}
        </main>

        {/* Right Sidebar (News/Trends) - Hidden on smaller maps view if space is tight */}
        {currentView !== View.MAP && (
          <Trends />
        )}
      </div>

      {/* Mobile Bottom Navigation */}
      <div className="sm:hidden fixed bottom-0 w-full bg-white border-t border-gray-200 flex justify-between px-2 pb-safe z-50">
        <MobileNavItem view={View.HOME} icon={Home} label="Início" />
        <MobileNavItem view={View.MAP} icon={MapIcon} label="Mapa" />
        <MobileNavItem view={View.NOTIFICATIONS} icon={Bell} label="Avisos" />
        <MobileNavItem view={View.PROFILE} icon={User} label="Perfil" />
      </div>
    </div>
  );
};

