export enum MapCategory {
  MEETING_POINT = 'Ponto de Encontro',
  DONATION = 'Doações/Coleta',
  MST_COMMUNITY = 'Comunidade MST',
  LEADERSHIP = 'Liderança PT',
  EVENT = 'Evento'
}

export interface User {
  id: string;
  name: string;
  handle: string;
  avatar: string;
  banner?: string;
  bio?: string;
  joinedDate?: string;
  following?: number;
  followers?: string;
  isVerified?: boolean;
}

export interface Post {
  id: string;
  user: User;
  content: string;
  timestamp: string;
  likes: string; // Changed to string to support "10K" format
  comments: string;
  retweets: string;
  views?: string;
  image?: string;
  isRepost?: boolean;
  repostUser?: string;
}

export interface MapPoint {
  id: string;
  lat: number;
  lng: number;
  title: string;
  description: string;
  category: MapCategory;
  address?: string;
}

export interface Trend {
  id: string;
  category: string;
  topic: string;
  postsCount: string;
}

export interface Notification {
  id: string;
  type: 'like' | 'retweet' | 'follow' | 'mention';
  user: User;
  content?: string; // For mentions
  postContent?: string; // For likes/retweets
  timestamp: string;
}

// Novos Tipos para Ações e Mobilização
export interface ActionEvent {
  id: string;
  title: string;
  location: string;
  date: string;
  organizer: string;
  confirmedCount: number;
  image?: string;
  type: 'PROTEST' | 'MEETING';
  lat?: number; // Coordenadas para o mapa
  lng?: number;
}

export interface Petition {
  id: string;
  title: string;
  description: string;
  targetGoal: number;
  currentSignatures: number;
  createdBy: User;
}

export interface PollOption {
  id: string;
  text: string;
  votes: number;
  percent: number;
}

export interface Poll {
  id: string;
  question: string;
  options: PollOption[];
  totalVotes: number;
  createdBy: User;
  timeLeft: string;
}

export interface UniversityEntity {
  id: string;
  name: string;
  university: string;
  type: 'DCE' | 'CA';
  members: string;
}

export interface SocialAidInfo {
  id: string;
  title: string;
  description: string;
  type: 'BOLSA_FAMILIA' | 'AID_REQUEST' | 'INFO';
}

