            {activeTab === 'FOLLOWING' && (
              <div className="absolute bottom-0 w-16 h-1 bg-red-600 rounded-full"></div>
            )}
          </button>

          {/* Sort Filter Toggle (Only for FOR YOU) */}
          {activeTab === 'FOR_YOU' && (
            <button 
              onClick={() => setSortByPopularity(!sortByPopularity)}
