import React, { useState, useMemo } from 'react';
import { Heart, MessageCircle, Repeat2, Share2, Image as ImageIcon, Smile, MapPin, BarChart2, ArrowUpDown, X, Maximize2 } from 'lucide-react';
import { MOCK_POSTS, CURRENT_USER } from '../constants';
import { Post } from '../types';

export const Feed: React.FC = () => {
  const [posts, setPosts] = useState<Post[]>(MOCK_POSTS);
  const [newPostContent, setNewPostContent] = useState('');
  const [activeTab, setActiveTab] = useState<'FOR_YOU' | 'FOLLOWING'>('FOR_YOU');

  // States for new features
  const [fullscreenImage, setFullscreenImage] = useState<string | null>(null);
  const [sortByPopularity, setSortByPopularity] = useState(false);

  // Helper to parse "10K", "1.5M" to numbers for sorting
  const parseMetric = (val: string): number => {
    if (!val) return 0;
    const n = parseFloat(val.replace(/,/g, '.'));
    if (val.includes('M')) return n * 1000000;
    if (val.includes('K')) return n * 1000;
    return n;
  };

  const displayedPosts = useMemo(() => {
    let list = [...posts];
    if (activeTab === 'FOR_YOU' && sortByPopularity) {
       list.sort((a, b) => {
          const scoreA = parseMetric(a.likes) + parseMetric(a.retweets) * 2;
          const scoreB = parseMetric(b.likes) + parseMetric(b.retweets) * 2;
          return scoreB - scoreA;
       });
    }
    return list;
  }, [posts, activeTab, sortByPopularity]);

  const handlePost = () => {
    if (!newPostContent.trim()) return;

    const newPost: Post = {
      id: Date.now().toString(),
      user: CURRENT_USER,
      content: newPostContent,
      timestamp: 'Agora',
      likes: '0',
      comments: '0',
      retweets: '0',
      views: '1',
    };

    setPosts([newPost, ...posts]);
    setNewPostContent('');
  };

