                      <BarChart2 size={18} />
                    </div>
                    <span className="text-xs group-hover:text-blue-500 ml-1">{post.views}</span>
                  </div>

                  <div 
                    className="group flex items-center cursor-pointer"
                    onClick={handleShare}
                  >
                    <div className="p-2 group-hover:bg-blue-50 rounded-full transition-colors group-hover:text-blue-500">
                      <Share2 size={18} />
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </article>
        ))}
      </div>

      {/* FULLSCREEN IMAGE MODAL */}
      {fullscreenImage && (
         <div className="fixed inset-0 bg-black/90 z-[60] flex items-center justify-center p-4 animate-in fade-in duration-200" onClick={() => setFullscreenImage(null)}>
            <button className="absolute top-4 right-4 text-white p-2 hover:bg-white/20 rounded-full" onClick={() => setFullscreenImage(null)}>
               <X size={32} />
            </button>
            <img src={fullscreenImage} className="max-w-full max-h-full object-contain rounded-lg" onClick={(e) => e.stopPropagation()} />
         </div>
      )}
    </div>
  );
};

