                           {/* Dots */}
                           <div className="absolute bottom-2 left-1/2 -translate-x-1/2 flex gap-1.5">
                              {gallery.map((_, idx) => (
                                 <div key={idx} className={`w-1.5 h-1.5 rounded-full shadow-sm ${idx === currentImgIndex ? 'bg-white' : 'bg-white/50'}`}></div>
